// Filter even numbers, then square them
const numbers = [1, 2, 3, 4, 5, 6, 7, 8];

const result = numbers
  .filter(n => n % 2 === 0)
  .map(n => n ** 2);
console.log(result);  // [4, 16, 36, 64]

