class BankAccount {
  constructor(owner, balance = 0) {
    this.owner = owner;
    this.balance = balance;
  }

  deposit(amount) {
    this.balance += amount;
    return this.balance;
  }

  toString() {
    return 'Account(' + this.owner + ': ' + this.balance + ')';
  }
}
